CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "unaccent";
CREATE EXTENSION IF NOT EXISTS "pg_trgm";
CREATE TYPE user_role AS ENUM ('visitor', 'contributor', 'moderator', 'admin');
CREATE TYPE media_type AS ENUM ('image', 'video', 'audio', 'document');
CREATE TYPE missing_status AS ENUM ('searching', 'found_alive', 'found_deceased', 'closed');
CREATE TYPE help_location_type AS ENUM ('shelter', 'hospital', 'water', 'food', 'rescue', 'evacuation');
CREATE TYPE organization_type AS ENUM ('ngo', 'government', 'religious', 'community', 'international');
CREATE TYPE donation_status AS ENUM ('pending', 'confirmed', 'failed', 'refunded');
CREATE TABLE users (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name VARCHAR(120) NOT NULL, email VARCHAR(254) UNIQUE, password_hash TEXT, role user_role NOT NULL DEFAULT 'visitor', country_code CHAR(2), language CHAR(2) NOT NULL DEFAULT 'es', avatar_url TEXT, bio TEXT, is_verified BOOLEAN NOT NULL DEFAULT false, is_active BOOLEAN NOT NULL DEFAULT true, last_login_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE candles (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID REFERENCES users(id) ON DELETE SET NULL, victim_name VARCHAR(200) NOT NULL, victim_age SMALLINT CHECK (victim_age >= 0 AND victim_age <= 150), victim_location VARCHAR(200), message TEXT, photo_url TEXT, is_approved BOOLEAN NOT NULL DEFAULT false, is_featured BOOLEAN NOT NULL DEFAULT false, moderated_by UUID REFERENCES users(id) ON DELETE SET NULL, moderated_at TIMESTAMPTZ, rejection_reason TEXT, flame_count INTEGER NOT NULL DEFAULT 0, ip_hash TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_candles_approved ON candles(is_approved, created_at DESC);
CREATE INDEX idx_candles_featured ON candles(is_featured, flame_count DESC);
CREATE INDEX idx_candles_user ON candles(user_id);
CREATE TABLE candle_flames (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), candle_id UUID NOT NULL REFERENCES candles(id) ON DELETE CASCADE, user_id UUID REFERENCES users(id) ON DELETE SET NULL, ip_fingerprint TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(candle_id, ip_fingerprint));
CREATE INDEX idx_flames_candle ON candle_flames(candle_id);
CREATE TABLE condolence_messages (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID REFERENCES users(id) ON DELETE SET NULL, candle_id UUID REFERENCES candles(id) ON DELETE CASCADE, content TEXT NOT NULL, author_name VARCHAR(120), author_country CHAR(2), is_approved BOOLEAN NOT NULL DEFAULT false, is_pinned BOOLEAN NOT NULL DEFAULT false, ip_hash TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_messages_candle ON condolence_messages(candle_id, is_approved);
CREATE INDEX idx_messages_approved ON condolence_messages(is_approved, created_at DESC);
CREATE TABLE testimonies (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), user_id UUID REFERENCES users(id) ON DELETE SET NULL, content TEXT NOT NULL, media_url TEXT, media_type media_type, location_name VARCHAR(200), state VARCHAR(100), latitude DECIMAL(9,6), longitude DECIMAL(9,6), is_approved BOOLEAN NOT NULL DEFAULT false, is_featured BOOLEAN NOT NULL DEFAULT false, moderated_by UUID REFERENCES users(id) ON DELETE SET NULL, author_name VARCHAR(120), allow_media BOOLEAN NOT NULL DEFAULT true, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_testimonies_approved ON testimonies(is_approved, created_at DESC);
CREATE INDEX idx_testimonies_location ON testimonies(latitude, longitude) WHERE latitude IS NOT NULL;
CREATE TABLE help_locations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name VARCHAR(200) NOT NULL, type help_location_type NOT NULL, address TEXT, state VARCHAR(100), city VARCHAR(100), latitude DECIMAL(9,6) NOT NULL, longitude DECIMAL(9,6) NOT NULL, description TEXT, phone VARCHAR(30), capacity INTEGER, current_load INTEGER, is_active BOOLEAN NOT NULL DEFAULT true, is_verified BOOLEAN NOT NULL DEFAULT false, verified_by UUID REFERENCES users(id) ON DELETE SET NULL, source_url TEXT, last_updated_by UUID REFERENCES users(id) ON DELETE SET NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_help_locations_geo ON help_locations(latitude, longitude);
CREATE INDEX idx_help_locations_type ON help_locations(type, is_active);
CREATE INDEX idx_help_locations_state ON help_locations(state, is_active);
CREATE TABLE organizations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name VARCHAR(200) NOT NULL, type organization_type NOT NULL, website TEXT, contact_email VARCHAR(254), phone VARCHAR(30), description TEXT NOT NULL, logo_url TEXT, country_code CHAR(2) NOT NULL DEFAULT 'VE', is_verified BOOLEAN NOT NULL DEFAULT false, is_active BOOLEAN NOT NULL DEFAULT true, verified_by UUID REFERENCES users(id) ON DELETE SET NULL, donation_url TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_orgs_verified ON organizations(is_verified, is_active);
CREATE INDEX idx_orgs_type ON organizations(type);
CREATE TABLE donations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, platform VARCHAR(50) NOT NULL, external_id VARCHAR(200), currency CHAR(3) NOT NULL DEFAULT 'USD', amount DECIMAL(12,2), donor_country CHAR(2), status donation_status NOT NULL DEFAULT 'pending', metadata JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_donations_org ON donations(organization_id, status);
CREATE TABLE missing_persons (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), reporter_id UUID REFERENCES users(id) ON DELETE SET NULL, full_name VARCHAR(200) NOT NULL, age SMALLINT, gender VARCHAR(20), last_seen_location VARCHAR(200), last_seen_state VARCHAR(100), photo_url TEXT, description TEXT, contact_info TEXT, status missing_status NOT NULL DEFAULT 'searching', resolution_note TEXT, is_approved BOOLEAN NOT NULL DEFAULT false, ip_hash TEXT, last_seen_at TIMESTAMPTZ, resolved_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_missing_status ON missing_persons(status, is_approved);
CREATE TABLE media_archive (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), uploaded_by UUID REFERENCES users(id) ON DELETE SET NULL, title VARCHAR(300) NOT NULL, description TEXT, file_url TEXT NOT NULL, thumbnail_url TEXT, file_type media_type NOT NULL, file_size_kb INTEGER, source VARCHAR(200), source_url TEXT, location_name VARCHAR(200), state VARCHAR(100), is_verified BOOLEAN NOT NULL DEFAULT false, is_sensitive BOOLEAN NOT NULL DEFAULT false, is_public BOOLEAN NOT NULL DEFAULT true, verified_by UUID REFERENCES users(id) ON DELETE SET NULL, event_timestamp TIMESTAMPTZ, tags TEXT[], created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_media_type ON media_archive(file_type, is_verified);
CREATE INDEX idx_media_verified ON media_archive(is_verified, is_public);
CREATE INDEX idx_media_tags ON media_archive USING gin(tags);
CREATE TABLE timeline_events (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), title VARCHAR(300) NOT NULL, description TEXT NOT NULL, event_type VARCHAR(50) NOT NULL, magnitude DECIMAL(3,1), location_name VARCHAR(200), latitude DECIMAL(9,6), longitude DECIMAL(9,6), depth_km DECIMAL(5,1), source VARCHAR(200), source_url TEXT, media_url TEXT, is_published BOOLEAN NOT NULL DEFAULT false, occurred_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX idx_timeline_occurred ON timeline_events(occurred_at, is_published);
CREATE OR REPLACE FUNCTION update_updated_at() RETURNS TRIGGER AS $$ BEGIN NEW.updated_at = NOW(); RETURN NEW; END; $$ LANGUAGE plpgsql;
DO $$ DECLARE t TEXT; BEGIN FOREACH t IN ARRAY ARRAY['users','candles','testimonies','help_locations','organizations','missing_persons'] LOOP EXECUTE format('CREATE TRIGGER trg_%I_updated_at BEFORE UPDATE ON %I FOR EACH ROW EXECUTE FUNCTION update_updated_at()', t, t); END LOOP; END; $$;
CREATE OR REPLACE FUNCTION sync_flame_count() RETURNS TRIGGER AS $$ BEGIN IF TG_OP = 'INSERT' THEN UPDATE candles SET flame_count = flame_count + 1 WHERE id = NEW.candle_id; ELSIF TG_OP = 'DELETE' THEN UPDATE candles SET flame_count = GREATEST(0, flame_count - 1) WHERE id = OLD.candle_id; END IF; RETURN NULL; END; $$ LANGUAGE plpgsql;
CREATE TRIGGER trg_flame_count AFTER INSERT OR DELETE ON candle_flames FOR EACH ROW EXECUTE FUNCTION sync_flame_count();
CREATE OR REPLACE FUNCTION immutable_unaccent(text) RETURNS text AS $$ SELECT unaccent($1); $$ LANGUAGE sql IMMUTABLE STRICT PARALLEL SAFE;
